(122,1,'2026-05-21 02:28:50','2026-05-21 02:28:50','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\"><strong>Vicken Cheterian</strong></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Background:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Lebanese-born journalist, author, and academic of Armenian descent [[1]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Holds a PhD from the Graduate Institute of International and Development Studies (IUHEI), Geneva [[4]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Writes in Western Armenian (Վիգէն Չըթըրեան) and Eastern Armenian (Վիգեն Չըթըրյան) [[1]]</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Current Positions:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Lecturer in international relations at <strong>Webster University Geneva</strong> [[3]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Lecturer in history and international relations at the <strong>University of Geneva</strong> [[4]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Columnist for the Istanbul-based Armenian-Turkish weekly <strong><em>Agos</em></strong> [[5]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Associate Fellow with the Global Fellowship Initiative at the <strong>Geneva Centre for Security Policy (GCSP)</strong> [[20]]</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\"><strong>Areas of Expertise</strong></h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Dr. Cheterian specializes in the study of <strong>violent conflicts</strong>, with extensive fieldwork across:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Post-Soviet states</strong>: Caucasus, Central Asia, Ukraine, Russia</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Middle East and North Africa</strong>: Syria, Lebanon, Turkey, Iraq</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Research Focus:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Civil wars and ethnic conflict [[20]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Nationalism, sectarianism, and jihadism [[20]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Genocide studies and historical memory [[20]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Transition politics and post-socialist revolutions [[4]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Peacebuilding and conflict prevention [[20]]</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Current Research:</strong> Evolution of sectarianism in the modern Middle East [[20]]</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\"><strong>Major Publications</strong></h3>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\"><strong>Books:</strong></h4>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>\"War and Peace in the Caucasus: Russia\'s Troubled Frontier\"</strong> (2008/2009)</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Published by Columbia University Press and Hurst [[6]][[20]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Analyzes ethnic conflicts and geopolitical dynamics in the Caucasus region</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>\"From Perestroika to Rainbow Revolutions: Reform and Revolution After Socialism\"</strong> (Editor, 2013)</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Published by Hurst [[4]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Examines political transformations across post-Soviet space</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>\"Open Wounds: Armenians, Turks and a Century of Genocide\"</strong> (2015)</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Published by Hurst and Oxford University Press [[9]][[25]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Explores how silence and complicity regarding mass violence affect societies across generations [[25]]</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>\"The 44-Day War: Armenia, Azerbaijan, and the Struggle for Nagorno-Karabakh\"</strong> (Editor, 2024)</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Open-access academic volume on the 2020 Nagorno-Karabakh war [[24]]</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\"><strong>Selected Academic Articles:</strong></h4>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>\"Roots of ISIS Violence and the Killing Fields of the Middle East,\" <em>Survival</em> (2015) [[4]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>\"Origins and Trajectory of the Conflicts in the Caucasus,\" <em>Europe-Asia Studies</em> (2012) [[4]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>\"Karabakh Conflict After Kosovo: No Way Out?,\" <em>Nationalities Papers</em> (2012) [[4]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>\"The August 2008 War in Georgia: from ethnic conflict to border wars,\" <em>Central Asian Survey</em> (2009) [[4]]</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\"><strong>Public Commentary:</strong></h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Regular contributor to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>openDemocracy</em> [[3]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Le Monde diplomatique</em>, <em>Neue Zürcher Zeitung</em>, <em>Al-Hayat</em> [[20]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Al Jazeera</em>, <em>SpecialEurasia</em>, <em>Baku Research Institute</em> [[7]][[10]]</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\"><strong>Policy and Practical Engagement</strong></h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Advisory Roles:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Advised governmental agencies and international organizations including:</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Swiss Federal Department of Foreign Affairs</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Swiss Agency for Development and Cooperation</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>UNEP, UNDP, World Bank, OSCE, European Commission\'s ECHO, International Criminal Court [[20]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Served as policy and media advisor on <strong>two UN Commissions of Inquiry</strong> [[20]]</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Peacebuilding Work:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Involved in development-focused peacebuilding projects across the Middle East, Caucasus, and Central Asia [[20]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Emphasizes the role of development initiatives in sustainable conflict resolution [[20]]</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\"><strong>Relevance to Ukraine and Eastern Europe</strong></h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>While Dr. Cheterian\'s primary regional focus is the <strong>South Caucasus</strong>, his analytical framework on:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Russian foreign policy</strong> and its use of \"frozen conflicts\" as leverage [[11]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ethnic nationalism</strong> and post-Soviet state formation [[4]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Gray zone warfare</strong> and hybrid conflict strategies [[17]]</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Historical memory</strong> and its instrumentalization in contemporary politics [[4]]</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>…provides essential context for understanding the broader dynamics of the <strong>Russo-Ukrainian War</strong> and Russia\'s approach to its \"near abroad.\"</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>His comparative analysis of the 2008 Georgia-Russia war and the 2020 Nagorno-Karabakh war highlights recurring patterns: receding Western influence, timing of offensives around U.S. elections, and the urgent need for independent war crimes documentation [[openDemocracy]].</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\"><strong>Connection to the Broader Group</strong></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Together with the previously discussed figures:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Person</th><th>Primary Lens on Eastern Europe/Ukraine</th></tr></thead><tbody><tr><td><strong>Kurt Volker</strong></td><td>U.S. diplomatic engagement and negotiation frameworks</td></tr><tr><td><strong>Arkady Babchenko</strong></td><td>On-the-ground Russian dissent and Ukrainian media perspective</td></tr><tr><td><strong>Anne Applebaum</strong></td><td>Historical scholarship on Soviet repression and authoritarianism</td></tr><tr><td><strong>Oleg Sentsov</strong></td><td>Lived experience of occupation, resistance, and military defense</td></tr><tr><td><strong>Vicken Cheterian</strong></td><td>Comparative conflict analysis, post-Soviet transition, and genocide studies</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:paragraph -->\n<p>Cheterian adds critical <strong>academic depth and comparative regional perspective</strong>, helping contextualize Ukraine\'s struggle within broader patterns of post-Soviet conflict, Russian imperial strategy, and the international community\'s often inconsistent responses to aggression and human rights violations.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><em>For further reading: See his articles at <a href=\"https://www.opendemocracy.net/author/vicken-cheterian/\">openDemocracy</a> and <a href=\"https://www.gcsp.ch/experts/dr-vicken-cheterian\">GCSP</a>, or his books through Hurst Publishers and Oxford University Press.</em></p>\n<!-- /wp:paragraph -->','Vicken Cheterian','','trash','closed','closed','','vicken-cheterian__trashed','','','2026-05-21 13:35:31','2026-05-21 13:35:31','',0,'https://ongoingstoriesofmysoul.org/?page_id=122',0,'page','',0),
